import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ===== QUOTE: simplest cases =====
  describe("quote — empty and edge cases", () => {
    it.todo("empty item list returns premium 5 G (only the processing fee)");
  });

  // ===== QUOTE: single main items, base premiums + first-insurance + fee =====
  describe("quote — single main items (newcomer, plain)", () => {
    it.todo("plain sword for a newcomer first insurance returns 115 G (100 base + 10 first-insurance + 5 fee)");
    it.todo("plain amulet for a newcomer first insurance returns 71 G (60 base + 6 first-insurance + 5 fee)");
    it.todo("plain staff for a newcomer first insurance returns 93 G (80 base + 8 first-insurance + 5 fee)");
    it.todo("plain potion for a newcomer first insurance returns 49 G (40 base + 4 first-insurance + 5 fee)");
  });

  // ===== QUOTE: components (runes, moonstones) =====
  describe("quote — components and building blocks", () => {
    it.todo("2 runes base premium is 50 G (2 × 25, no block)");
    it.todo("3 runes base premium is 60 G (block discount applies)");
    it.todo("4 runes base premium is 100 G (4 × 25, no block — block requires exactly 3)");
    it.todo("7 runes base premium is 175 G (7 × 25, no block formed across 3+3+1)");
    it.todo("2 runes + 1 moonstone base premium is 75 G (no block: different types)");
    it.todo("3 runes + 3 moonstones base premium is 120 G (two separate blocks of 60 G each)");
  });

  // ===== QUOTE: item-specific modifiers =====
  describe("quote — item-specific modifiers (cursed, high enchantment)", () => {
    it.todo("cursed sword (enchantment 3) for newcomer returns 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)");
    it.todo("sword with exactly enchantment 5 gets the high-enchantment surcharge");
    it.todo("sword with enchantment 4 does NOT get the high-enchantment surcharge");
    it.todo("cursed sword with enchantment 5 gets BOTH cursed and high-enchantment surcharges");
  });

  // ===== QUOTE: modifier scope on multi-item policies =====
  describe("quote — modifier scope on multi-item policies", () => {
    it.todo("policy with cursed sword + plain amulet has policy base premium 160 G; cursed adds 50 G (50% of cursed sword's base) → 210 G before policy modifiers and fee");
  });

  // ===== QUOTE: policy-wide modifiers (loyalty, first-insurance, follow-up) =====
  describe("quote — policy-wide modifiers", () => {
    it.todo("customer with exactly 2 years with MHPCO gets the 20% loyalty discount");
    it.todo("customer with less than 2 years does NOT get the loyalty discount");
    it.todo("follow-up contract (customer's second quote in scenario) gets the 15% discount");
    it.todo("each new item in a quote is treated as a first insurance regardless of customer history");
  });

  // ===== QUOTE: rounding =====
  describe("quote — rounding", () => {
    it.todo("premium calculation yielding 197.5 G rounds UP to 198 G (in MHPCO's favor)");
    it.todo("intermediate amounts are kept as fractions; only the final premium is rounded");
  });

  // ===== QUOTE: integration examples =====
  describe("quote — integration examples", () => {
    it.todo("newcomer (0 years, no previous contract) with cursed sword (steel, enchantment 3) → premium 165 G");
    it.todo("3-year customer's second quote with cursed sword (steel, enchantment 7) → premium 160 G (100 base + 50 curse + 30 high-enchant − 20 loyalty + 10 first-insurance − 15 follow-up + 5 fee)");
  });

  // ===== QUOTE: errors =====
  describe("quote — errors", () => {
    it.todo("unknown item type (e.g. broomstick) throws / returns error");
  });

  // ===== CLAIM: standard reimbursement =====
  describe("claim — standard reimbursement (no special clauses)", () => {
    it.todo("regular sword (steel, enchantment 3) with damage 500 G → payout 400 G (500 − 100 deductible)");
    it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (200 − 100 deductible)");
  });

  // ===== CLAIM: enchantment clause =====
  describe("claim — high-enchantment clause (≥8)", () => {
    it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then 100 deductible)");
    it.todo("steel sword, enchantment 8, damage 1000 G → payout 400 G (50% then 100 deductible)");
  });

  // ===== CLAIM: dragon material clause =====
  describe("claim — dragon material clause", () => {
    it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement, then 100 deductible)");
  });

  // ===== CLAIM: dragon vs enchantment precedence =====
  describe("claim — dragon vs enchantment precedence (50% rule wins)", () => {
    it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (both apply; 50% rule wins, then deductible)");
  });

  // ===== CLAIM: deductible per damage event =====
  describe("claim — deductible per damage event", () => {
