const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

export function quote(input: { customer: { yearsWithMHPCO: number; previousContract: boolean }; items: { type: string }[] }): number {
  if (input.items.length === 0) return PROCESSING_FEE;
  const groups = new Map<string, number>();
  for (const item of input.items) {
    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
  }
  let basePremium = 0;
  for (const [type, count] of groups) {
    if (COMPONENT_TYPES.has(type) && count === 3) {
      basePremium += 60;
    } else {
      basePremium += count * BASE_PREMIUM_BY_TYPE[type];
    }
  }
  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
  return Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);
}

export function claim(..._args: unknown[]): unknown {
  throw new Error("not implemented");
