const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

export function quote(input: { customer: { yearsWithMHPCO: number; previousContract: boolean }; items: { type: string; cursed?: boolean }[] }): number {
  if (input.items.length === 0) return PROCESSING_FEE;
  const groups = new Map<string, { type: string; cursed?: boolean }[]>();
  for (const item of input.items) {
    const list = groups.get(item.type) ?? [];
    list.push(item);
    groups.set(item.type, list);
  }
  let basePremium = 0;
  let firstInsurance = 0;
  for (const [type, items] of groups) {
    const count = items.length;
    if (COMPONENT_TYPES.has(type) && count === 3) {
      basePremium += 60;
      firstInsurance += 60 * FIRST_INSURANCE_RATE;
    } else {
      for (const item of items) {
        const itemBase = BASE_PREMIUM_BY_TYPE[type];
        let itemContribution = itemBase;
        if (item.cursed) {
          itemContribution += itemBase * 0.5;
        }
        basePremium += itemContribution;
        firstInsurance += itemBase * FIRST_INSURANCE_RATE;
      }
    }
  }
  return Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);
}

export function claim(..._args: unknown[]): unknown {
  throw new Error("not implemented");
